169	void
170	njs_disassembler(njs_vm_t *vm)
171	{
172	    njs_uint_t     n;
173	    njs_vm_code_t  *code;
174	
175	    code = vm->codes->start;
176	    n = vm->codes->items;
177	
178	    while (n != 0) {
179	        njs_printf("%V:%V\n", &code->file, &code->name);
180	        njs_disassemble(code->start, code->end, -1, code->lines);
181	        code++;
182	        n--;
183	    }
184	
185	    njs_printf("\n");
186	}
187	
188	
189	void
190	njs_disassemble(u_char *start, u_char *end, njs_int_t count, njs_arr_t *lines)
191	{
192	    u_char                       *p;
193	    uint32_t                     line;
194	    njs_str_t                    *name;
195	    njs_uint_t                   n;
196	    const char                   *type;
197	    njs_vmcode_t                 operation;
198	    njs_code_name_t              *code_name;
199	    njs_vmcode_jump_t            *jump;
200	    njs_vmcode_error_t           *error;
201	    njs_vmcode_1addr_t           *code1;
202	    njs_vmcode_2addr_t           *code2;
203	    njs_vmcode_3addr_t           *code3;
204	    njs_vmcode_array_t           *array;
205	    njs_vmcode_catch_t           *catch;
206	    njs_vmcode_import_t          *import;
207	    njs_vmcode_finally_t         *finally;
208	    njs_vmcode_try_end_t         *try_end;
209	    njs_vmcode_try_start_t       *try_start;
210	    njs_vmcode_cond_jump_t       *cond_jump;
211	    njs_vmcode_test_jump_t       *test_jump;
212	    njs_vmcode_prop_next_t       *prop_next;
213	    njs_vmcode_try_return_t      *try_return;
214	    njs_vmcode_equal_jump_t      *equal;
215	    njs_vmcode_prop_foreach_t    *prop_foreach;
216	    njs_vmcode_method_frame_t    *method;
217	    njs_vmcode_prop_accessor_t   *prop_accessor;
218	    njs_vmcode_try_trampoline_t  *try_tramp;
219	    njs_vmcode_function_frame_t  *function;
220	
221	    /*
222	     * On some 32-bit platform uintptr_t is int and compilers warn
223	     * about %l format modifier.  size_t has the size as pointer so
224	     * there is no run-time overhead.
225	     */
226	
227	    p = start;
228	
229	    while (((p < end) && (count == -1)) || (count-- > 0)) {
230	        operation = *(njs_vmcode_t *) p;
231	        line = njs_lookup_line(lines, p - start);
232	
233	        if (operation == NJS_VMCODE_ARRAY) {
234	            array = (njs_vmcode_array_t *) p;
235	
236	            njs_printf("%5uD | %05uz ARRAY             %04Xz %uz%s\n",
237	                       line, p - start, (size_t) array->retval,
238	                       (size_t) array->length, array->ctor ? " INIT" : "");
239	
240	            p += sizeof(njs_vmcode_array_t);
241	
242	            continue;
243	        }
244	
245	        if (operation == NJS_VMCODE_IF_TRUE_JUMP) {
246	            cond_jump = (njs_vmcode_cond_jump_t *) p;
247	
248	            njs_printf("%5uD | %05uz JUMP IF TRUE      %04Xz %z\n",
249	                       line, p - start, (size_t) cond_jump->cond,
250	                       (size_t) cond_jump->offset);
251	
252	            p += sizeof(njs_vmcode_cond_jump_t);
253	
254	            continue;
255	        }
256	
257	        if (operation == NJS_VMCODE_IF_FALSE_JUMP) {
258	            cond_jump = (njs_vmcode_cond_jump_t *) p;
259	
260	            njs_printf("%5uD | %05uz JUMP IF FALSE     %04Xz %z\n",
261	                       line, p - start, (size_t) cond_jump->cond,
262	                       (size_t) cond_jump->offset);
263	
264	            p += sizeof(njs_vmcode_cond_jump_t);
265	
266	            continue;
267	        }
268	
269	        if (operation == NJS_VMCODE_JUMP) {
270	            jump = (njs_vmcode_jump_t *) p;
271	
272	            njs_printf("%5uD | %05uz JUMP              %z\n",
273	                       line, p - start, (size_t) jump->offset);
274	
275	            p += sizeof(njs_vmcode_jump_t);
276	
277	            continue;
278	        }
279	
280	        if (operation == NJS_VMCODE_IF_EQUAL_JUMP) {
281	            equal = (njs_vmcode_equal_jump_t *) p;
282	
283	            njs_printf("%5uD | %05uz JUMP IF EQUAL     %04Xz %04Xz %z\n",
284	                       line, p - start, (size_t) equal->value1,
285	                       (size_t) equal->value2, (size_t) equal->offset);
286	
287	            p += sizeof(njs_vmcode_equal_jump_t);
288	
289	            continue;
290	        }
291	
292	        if (operation == NJS_VMCODE_TEST_IF_TRUE) {
293	            test_jump = (njs_vmcode_test_jump_t *) p;
294	
295	            njs_printf("%5uD | %05uz TEST IF TRUE      %04Xz %04Xz %z\n",
296	                       line, p - start, (size_t) test_jump->retval,
297	                       (size_t) test_jump->value, (size_t) test_jump->offset);
298	
299	            p += sizeof(njs_vmcode_test_jump_t);
300	
301	            continue;
302	        }
303	
304	        if (operation == NJS_VMCODE_TEST_IF_FALSE) {
305	            test_jump = (njs_vmcode_test_jump_t *) p;
306	
307	            njs_printf("%5uD | %05uz TEST IF FALSE     %04Xz %04Xz %z\n",
308	                       line, p - start, (size_t) test_jump->retval,
309	                       (size_t) test_jump->value, (size_t) test_jump->offset);
310	
311	            p += sizeof(njs_vmcode_test_jump_t);
312	
313	            continue;
314	        }
315	
316	        if (operation == NJS_VMCODE_COALESCE) {
317	            test_jump = (njs_vmcode_test_jump_t *) p;
318	
319	            njs_printf("%5uD | %05uz COALESCE          %04Xz %04Xz %z\n",
320	                       line, p - start, (size_t) test_jump->retval,
321	                       (size_t) test_jump->value, (size_t) test_jump->offset);
322	
323	            p += sizeof(njs_vmcode_test_jump_t);
324	
325	            continue;
326	        }
327	
328	        if (operation == NJS_VMCODE_OPTIONAL_CHAIN) {
329	            test_jump = (njs_vmcode_test_jump_t *) p;
330	
331	            njs_printf("%5uD | %05uz OPTIONAL CHAIN    "
332	                       "%04Xz %04Xz %z\n",
333	                       line, p - start,
334	                       (size_t) test_jump->retval,
335	                       (size_t) test_jump->value,
336	                       (size_t) test_jump->offset);
337	
338	            p += sizeof(njs_vmcode_test_jump_t);
339	
340	            continue;
341	        }
342	
343	        if (operation == NJS_VMCODE_FUNCTION_FRAME) {
344	            function = (njs_vmcode_function_frame_t *) p;
345	
346	            njs_printf("%5uD | %05uz FUNCTION FRAME    %04Xz %uz%s\n",
347	                       line, p - start, (size_t) function->name,
348	                       function->nargs, function->ctor ? " CTOR" : "");
349	
350	            p += sizeof(njs_vmcode_function_frame_t);
351	
352	            continue;
353	        }
354	
355	        if (operation == NJS_VMCODE_METHOD_FRAME) {
356	            method = (njs_vmcode_method_frame_t *) p;
357	
358	            njs_printf("%5uD | %05uz METHOD FRAME      %04Xz %04Xz %uz%s\n",
359	                       line, p - start, (size_t) method->function,
360	                       (size_t) method->this_object, method->nargs,
361	                       method->ctor ? " CTOR" : "");
362	
363	            p += sizeof(njs_vmcode_method_frame_t);
364	            continue;
365	        }
366	
367	        if (operation == NJS_VMCODE_PROPERTY_FOREACH) {
368	            prop_foreach = (njs_vmcode_prop_foreach_t *) p;
369	
370	            njs_printf("%5uD | %05uz PROP FOREACH      %04Xz %04Xz %z\n",
371	                       line, p - start, (size_t) prop_foreach->next,
372	                       (size_t) prop_foreach->object,
373	                       (size_t) prop_foreach->offset);
374	
375	            p += sizeof(njs_vmcode_prop_foreach_t);
376	            continue;
377	        }
378	
379	        if (operation == NJS_VMCODE_PROPERTY_NEXT) {
380	            prop_next = (njs_vmcode_prop_next_t *) p;
381	
382	            njs_printf("%5uD | %05uz PROP NEXT         %04Xz %04Xz %04Xz %z\n",
383	                       line, p - start, (size_t) prop_next->retval,
384	                       (size_t) prop_next->object, (size_t) prop_next->next,
385	                       (size_t) prop_next->offset);
386	
387	            p += sizeof(njs_vmcode_prop_next_t);
388	
389	            continue;
390	        }
391	
392	        if (operation == NJS_VMCODE_PROPERTY_ACCESSOR) {
393	            prop_accessor = (njs_vmcode_prop_accessor_t *) p;
394	
395	            njs_printf("%5uD | %05uz PROP %s ACCESSOR %04Xz %04Xz %04Xz\n",
396	                       line, p - start,
397	                       (prop_accessor->type == NJS_OBJECT_PROP_GETTER)
398	                           ? "GET" : "SET",
399	                       (size_t) prop_accessor->value,
400	                       (size_t) prop_accessor->object,
401	                       (size_t) prop_accessor->property);
402	
403	            p += sizeof(njs_vmcode_prop_accessor_t);
404	
405	            continue;
406	        }
407	
408	        if (operation == NJS_VMCODE_IMPORT) {
409	            import = (njs_vmcode_import_t *) p;
410	
411	            njs_printf("%5uD | %05uz IMPORT            %04Xz %V\n",
412	                       line, p - start, (size_t) import->retval,
413	                       &import->module->name);
414	
415	            p += sizeof(njs_vmcode_import_t);
416	
417	            continue;
418	        }
419	
420	        if (operation == NJS_VMCODE_TRY_START) {
421	            try_start = (njs_vmcode_try_start_t *) p;
422	
423	            njs_printf("%5uD | %05uz TRY START         %04Xz %04Xz %z\n",
424	                       line, p - start, (size_t) try_start->exception_value,
425	                       (size_t) try_start->exit_value,
426	                       (size_t) try_start->offset);
427	
428	            p += sizeof(njs_vmcode_try_start_t);
429	
430	            continue;
431	        }
432	
433	        if (operation == NJS_VMCODE_TRY_BREAK) {
434	            try_tramp = (njs_vmcode_try_trampoline_t *) p;
435	
436	            njs_printf("%5uD | %05uz TRY BREAK         %04Xz %z\n",
437	                       line, p - start, (size_t) try_tramp->exit_value,
438	                       (size_t) try_tramp->offset);
439	
440	            p += sizeof(njs_vmcode_try_trampoline_t);
441	
442	            continue;
443	        }
444	
445	        if (operation == NJS_VMCODE_TRY_CONTINUE) {
446	            try_tramp = (njs_vmcode_try_trampoline_t *) p;
447	
448	            njs_printf("%5uD | %05uz TRY CONTINUE      %04Xz %z\n",
449	                       line, p - start, (size_t) try_tramp->exit_value,
450	                       (size_t) try_tramp->offset);
451	
452	            p += sizeof(njs_vmcode_try_trampoline_t);
453	
454	            continue;
455	        }
456	
457	        if (operation == NJS_VMCODE_TRY_RETURN) {
458	            try_return = (njs_vmcode_try_return_t *) p;
459	
460	            njs_printf("%5uD | %05uz TRY RETURN        %04Xz %04Xz %z\n",
461	                       line, p - start, (size_t) try_return->save,
462	                       (size_t) try_return->retval,
463	                       (size_t) try_return->offset);
464	
465	            p += sizeof(njs_vmcode_try_return_t);
466	
467	            continue;
468	        }
469	
470	        if (operation == NJS_VMCODE_CATCH) {
471	            catch = (njs_vmcode_catch_t *) p;
472	
473	            njs_printf("%5uD | %05uz CATCH             %04Xz %z\n",
474	                       line, p - start, (size_t) catch->exception,
475	                       (size_t) catch->offset);
476	
477	            p += sizeof(njs_vmcode_catch_t);
478	
479	            continue;
480	        }
481	
482	        if (operation == NJS_VMCODE_TRY_END) {
483	            try_end = (njs_vmcode_try_end_t *) p;
484	
485	            njs_printf("%5uD | %05uz TRY END           %z\n",
486	                       line, p - start, (size_t) try_end->offset);
487	
488	            p += sizeof(njs_vmcode_try_end_t);
489	
490	            continue;
491	        }
492	
493	        if (operation == NJS_VMCODE_FINALLY) {
494	            finally = (njs_vmcode_finally_t *) p;
495	
496	            njs_printf("%5uD | %05uz TRY FINALLY       %04Xz %04Xz %z %z\n",
497	                       line, p - start, (size_t) finally->retval,
498	                       (size_t) finally->exit_value,
499	                       (size_t) finally->continue_offset,
500	                       (size_t) finally->break_offset);
501	
502	            p += sizeof(njs_vmcode_finally_t);
503	
504	            continue;
505	        }
506	
507	        if (operation == NJS_VMCODE_ERROR) {
508	            error = (njs_vmcode_error_t *) p;
509	
510	            switch (error->type) {
511	            case NJS_OBJ_TYPE_REF_ERROR:
512	                type = "REFERENCE";
513	                break;
514	
515	            case NJS_OBJ_TYPE_TYPE_ERROR:
516	                type = "TYPE";
517	                break;
518	
519	            case NJS_OBJ_TYPE_ERROR:
520	            default:
521	                type = "";
522	            }
523	
524	            njs_printf("%5uD | %05uz %s ERROR\n", line, p - start, type);
525	
526	            p += sizeof(njs_vmcode_error_t);
527	
528	            continue;
529	        }
530	
531	        code_name = code_names;
