        location /send {
            js_content test.send;
        }

        location /send_buffer {
            js_content test.send_buffer;
        }

        location /return_method {
            js_content test.return_method;
        }

        location /type {
            js_content test.type;
        }

        location /log {
            return 200 $test_log;
        }

        location /internal {
            js_content test.internal;
